import matplotlib.pyplot as plt

# Define region codes
INSIDE = 0  # 0000
LEFT = 1    # 0001
RIGHT = 2   # 0010
BOTTOM = 4  # 0100
TOP = 8     # 1000

# Clipping window boundaries
x_min, y_min = 50, 50
x_max, y_max = 150, 150

def compute_region_code(x, y):
    code = INSIDE
    if x < x_min:
        code |= LEFT
    elif x > x_max:
        code |= RIGHT
    if y < y_min:
        code |= BOTTOM
    elif y > y_max:
        code |= TOP
    return code

def cohen_sutherland_clip(x1, y1, x2, y2):
    code1 = compute_region_code(x1, y1)
    code2 = compute_region_code(x2, y2)

    accept = False

    while True:
        if code1 == 0 and code2 == 0:
            accept = True
            break
        elif (code1 & code2) != 0:
            break
        else:
            x, y = 0, 0
            if code1 != 0:
                code_out = code1
            else:
                code_out = code2

            if code_out & TOP:
                x = x1 + (x2 - x1) * (y_max - y1) / (y2 - y1)
                y = y_max
            elif code_out & BOTTOM:
                x = x1 + (x2 - x1) * (y_min - y1) / (y2 - y1)
                y = y_min
            elif code_out & RIGHT:
                y = y1 + (y2 - y1) * (x_max - x1) / (x2 - x1)
                x = x_max
            elif code_out & LEFT:
                y = y1 + (y2 - y1) * (x_min - x1) / (x2 - x1)
                x = x_min

            if code_out == code1:
                x1, y1 = x, y
                code1 = compute_region_code(x1, y1)
            else:
                x2, y2 = x, y
                code2 = compute_region_code(x2, y2)

    if accept:
        return x1, y1, x2, y2
    return None

# Example usage
lines = [
    (30, 30, 120, 120),
    (10, 100, 200, 100),
    (100, 10, 100, 200),
    (20, 20, 80, 80)
]

for i, (x1, y1, x2, y2) in enumerate(lines):
    result = cohen_sutherland_clip(x1, y1, x2, y2)
    if result:
        print(f"Line {i+1}: Clipped from ({x1},{y1})-({x2},{y2}) to ({result[0]:.1f},{result[1]:.1f})-({result[2]:.1f},{result[3]:.1f})")
    else:
        print(f"Line {i+1}: Completely outside, rejected")
